                  <ShotCard key={shot.id} shot={shot} onUpdateShot={onUpdateShot} onGenerateSpecificKeyframe={onGenerateSpecificKeyframe} onRefineShot={onRefineShot} allAssets={allAssets} onToggleAssetForShot={onToggleAssetForShot} onGenerateVideo={onGenerateVideo} onExtendVeoVideo={onExtendVeoVideo} mcpEnabled={mcpConfig.connected} onSyncToResolve={onSyncToResolve} />
