  keyframePromptText?: string;
  keyframeImage?: string;
  errorMessage?: string;
  selectedAssetIds: string[];
  guidanceFrameIds: string[]; // Reference to GuidanceFrame IDs
  veoTaskId?: string;
  veoStatus?: VeoStatus;
  veoVideoUrl?: string;
  veoError?: string;
  mcpSynced?: boolean;
}

